// HasDrawCycleWith applies the HasEdge predicate on the "draw_cycle" edge with a given conditions (other predicates).
func HasDrawCycleWith(preds ...predicate.ShopDrawCycle) predicate.ShopBalanceLedger {
	return predicate.ShopBalanceLedger(func(s *sql.Selector) {
		step := newDrawCycleStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ShopBalanceLedger) predicate.ShopBalanceLedger {
	return predicate.ShopBalanceLedger(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ShopBalanceLedger) predicate.ShopBalanceLedger {
	return predicate.ShopBalanceLedger(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ShopBalanceLedger) predicate.ShopBalanceLedger {
	return predicate.ShopBalanceLedger(sql.NotPredicates(p))
}
